import{_ as t,o as a,c as s,a6 as p,kx as o,ky as n,kz as e,iQ as i,iR as g,kA as l,kB as _,kc as c,kC as d,ka as m,kD as h}from"./chunks/framework.UYVGz2W_.js";const $=JSON.parse('{"title":"ビルドスタジオレポート","description":"","frontmatter":{},"headers":[],"relativePath":"ja/studio-report/index.md","filePath":"ja/studio-report/index.md"}'),k={name:"ja/studio-report/index.md"};function f(x,r,b,P,u,T){return a(),s("div",null,[...r[0]||(r[0]=[p('<h1 id="ビルドスタジオレポート" tabindex="-1">ビルドスタジオレポート <a class="header-anchor" href="#ビルドスタジオレポート" aria-label="Permalink to “ビルドスタジオレポート”">​</a></h1><h2 id="スタジオリソースの概要" tabindex="-1">スタジオリソースの概要 <a class="header-anchor" href="#スタジオリソースの概要" aria-label="Permalink to “スタジオリソースの概要”">​</a></h2><p>プロデューサーは、すべてを知っておく必要があります。</p><p>通常、これは多数の詳細を追跡し、制作チームとの複数の会議に出席し、常にすべてを自分で確認することを意味します。あるいは、すべてのタスクを購読して通知に圧倒されることもできますが、通知を読むために作業を中断するたびに集中力が途切れてしまいます。</p><p>完璧なソリューションは、すべての制作統計を1ページにまとめ、常に最新の状態にしておくことです。</p><p>ようこそ、<strong>すべてのタスク</strong>ページへ。</p><p><img src="'+o+'" alt="ニュースフィードスタジオページ"></p><p>ここでは、すべての制作物のステータスを一度に確認できます。<strong>制作</strong>、<strong>タスクステータス</strong>、<strong>タスクタイプ</strong>、<strong>担当者</strong>別にリストをフィルタリングできます。行をクリックすると、右側にコメントパネルが開き、必要なすべての情報を表示します。</p><p>より詳細な情報が必要な場合、特に特定の期間についての情報が必要な場合は、<strong>[スタジオ] &gt; [ニュースフィード]</strong> ページを使用できます。</p><p>[フィルタービルダー] ボタンを使用すると、特定の期間を定義することができます。</p><p><img src="'+n+'" alt="ニュースフィードスタジオの詳細ページ"></p><p>たとえば、特定の月のスーパーバイザーの作業負荷に焦点を当てたい場合は、スーパーバイザーの名前を選択し、<strong>[From]</strong>ボックスで日付を選択します。</p><p>すべての制作の現在の状態</p><p>スタジオが円滑に機能するためには、進行中のすべての制作を把握しておく必要があります。 <strong>制作</strong> セクションが役立ちます。グローバルメニューの <strong>スタジオ</strong> セクションからアクセスしてください。</p><p>そこから <strong>ロード統計</strong> ボタンをクリックすると、制作の現在の状態を確認できます。</p><p><img src="'+e+'" alt="制作統計"></p><p>さらに詳しい情報については、すべての制作の<strong>シーケンス統計</strong>ページと<strong>アセットタイプ統計</strong>ページをご覧ください。</p><h3 id="統計ページ" tabindex="-1">統計ページ <a class="header-anchor" href="#統計ページ" aria-label="Permalink to “統計ページ”">​</a></h3><p><strong>シーケンス統計</strong>ページでは、シーケンスごとに分類された制作全体の円グラフが1ページに表示されます。 円グラフの色分けはステータスに対応しており、制作の状態を素早く把握できます。</p><p>最初の行は<strong>すべてのシーケンス</strong>で、制作全体を表します。最初の列の<strong>すべて</strong>には、すべてのタスクが同時に含まれます。</p><p><img src="'+i+'" alt="シーケンス統計ページ"></p><p>この最初の円グラフに注目することで、制作の正確な状態を確認できます。さらに詳細を確認するには、各タスクタイプの状態の全体像を把握するために、その行の残りの部分を確認します。</p><p><strong>アセットタイプ統計</strong>ページでは、アセットについても同レベルの詳細情報を提供します。</p><p><img src="'+g+'" alt="アセットタイプ統計ページ"></p><p>また、<strong>カウント</strong>としてデータを表示し、ステータスごとの割合とともにショット/フレームの正確な数を示します。</p><p><img src="'+l+'" alt="アセットカウント統計ページ"></p><p>このページを <code>.csv</code> テキストファイルとしてエクスポートし、スプレッドシートソフトウェアにインポートすることもできます。</p><p>画面上部の <strong>ナビゲーション</strong> メニューを使用して、プロダクション間を移動します。同じページに留まり、各プロダクションを選択してすべてのプロダクション統計を確認できます。</p><p><img src="'+_+'" alt="シーケンス統計ナビゲーション"></p><h2 id="スタジオ稼働率" tabindex="-1">スタジオ稼働率 <a class="header-anchor" href="#スタジオ稼働率" aria-label="Permalink to “スタジオ稼働率”">​</a></h2><p><strong>チームスケジュール</strong>では、割り当てられたタスクを持つすべてのアーティストを確認できます。各行がアーティストを表し、アーティストの行を展開すると、そのアーティストのタスクの詳細が表示されます。</p><p><img src="'+c+'" alt="チームスケジュール"></p><h3 id="特定の時間枠に焦点を当てる" tabindex="-1">特定の時間枠に焦点を当てる <a class="header-anchor" href="#特定の時間枠に焦点を当てる" aria-label="Permalink to “特定の時間枠に焦点を当てる”">​</a></h3><p>開始日と終了日を設定することで、特定の時間枠に焦点を絞ることができます。 割り当てられたタスクの詳細情報を得るには、ズームレベルを調整します。 すべての<strong>部署</strong>を表示するか、特定の部署のみを表示するかを選択でき、特定の<strong>担当者</strong>に焦点を絞ることもできます。</p><p>アーティストが同じ日に複数のタスクを持っている場合、<strong>それぞれのタスクごとに1行</strong>でタスクが積み上げられます。</p><p><img src="'+d+'" alt="チームスケジュール フィルタリング"></p><h3 id="スケジュールの変更" tabindex="-1">スケジュールの変更 <a class="header-anchor" href="#スケジュールの変更" aria-label="Permalink to “スケジュールの変更”">​</a></h3><p>タスクを移動するには、タスクをドラッグして別の日に配置します。 チームスケジュールで変更した内容は、タスクタイプのスケジュールにも適用されます。</p><p>アーティストが2つのタスクの間に休憩を取った場合、サマリー行は中断されず、アーティストに割り当てられた最初のタスクと最後のタスクが表示されます。</p><h2 id="メインスケジュールを利用する" tabindex="-1">メインスケジュールを利用する <a class="header-anchor" href="#メインスケジュールを利用する" aria-label="Permalink to “メインスケジュールを利用する”">​</a></h2><p>メインスケジュール<strong>では、すべての</strong>制作スケジュール**に一度にアクセスすることができます。</p><p><img src="'+m+'" alt="メインスケジュール"></p><p>制作を展開すると、その制作で使用されている各<strong>タスクタイプ</strong>の詳細が表示されます。複数の制作を展開すると、同時にどのチームが稼働しているかを確認できます。</p><p><img src="'+h+'" alt="メインスケジュール展開"></p><p>各<strong>タスクタイプバー</strong>を移動して、スタジオのニーズに合わせたスケジュール調整を行うことができます。</p><p>::: 警告 変更はすべて制作スケジュールに適用されます。 :::</p>',46)])])}const A=t(k,[["render",f]]);export{$ as __pageData,A as default};
